Here is code for a Discord bot with a /ban slash command using Discord.js v14:

```js
const Discord = require('discord.js');
const client = new Discord.Client({ intents: [Discord.Intents.FLAGS.GUILDS, Discord.Intents.FLAGS.GUILD_MESSAGES] });

client.on('ready', () => {
  console.log('Ready!');
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  if (interaction.commandName === 'ban') {
    if (!interaction.member.permissions.has('BAN_MEMBERS')) {
      return await interaction.reply('You do not have permission to ban members.');
    }

    const user = interaction.options.getUser('user');
    const member = interaction.guild.members.cache.get(user.id);
    if (member) {
      try {
        await member.ban();
        await interaction.reply(`Successfully banned ${user.tag}`);
      } catch (err) {
        await interaction.reply('Unable to ban member.');
        console.error(err);
      }
    } else {
      await interaction.reply('Unable to find member.');
    }
  } 
});

client.login('your bot token here');
```

This bot:

- Logs in with a bot token 
- Registers a slash command interaction event listener
- Checks for the /ban command 
- Checks if the user has BAN_MEMBERS permission
- Gets the user to ban from the interaction options
- Tries to ban the member 
- Replies with a success/failure message

